import React, { useState, useRef, useEffect } from 'react';
import { 
  Upload, Image as ImageIcon, Sparkles, Download, RefreshCw, 
  AlertCircle, X, Box, User, Shirt, Hand, Layers 
} from 'lucide-react';

// --- Cấu hình API ---
const apiKey = ""; 

// Danh sách bối cảnh (Backdrops) - Đã thêm Gian bếp & Phòng khách Chung cư
const BACKDROPS = [
  { 
    id: 'cafe_outdoor', 
    label: 'Cafe Sân Vườn / Ngoài Trời', 
    desc: 'Tự nhiên, thoáng đãng, ánh sáng ban ngày.',
    prompt: 'An outdoor cafe patio or garden setting during the daytime. Natural sunlight, green foliage, blurred wooden tables and chairs in the background. Fresh and airy feel.'
  },
  { 
    id: 'lifestyle_home', 
    label: 'Không Gian Nhà Ấm Cúng', 
    desc: 'Bối cảnh đời thường, phòng khách hoặc góc decor gần gũi.',
    prompt: 'A warmly lit, realistic and cozy living room environment. Blurred background with soft textures, indoor plants, wooden furniture, and natural light coming from a window. Feels authentic and lived-in.'
  },
  { 
    id: 'apartment_living', 
    label: 'Phòng Khách Chung Cư', 
    desc: 'Hiện đại, sofa sang trọng, view cửa sổ thoáng.',
    prompt: 'A modern apartment living room background with contemporary furniture, a stylish sofa, and soft natural light entering through a large window (perhaps with a blurred city view). Clean, open-plan, and sophisticated urban vibe.'
  },
  { 
    id: 'apartment_kitchen', 
    label: 'Gian Bếp Chung Cư Hiện Đại', 
    desc: 'Tiện nghi, tủ bếp phẳng, ánh sáng hiện đại.',
    prompt: 'A sleek, modern apartment kitchen background. Clean countertops, built-in appliances, minimalist cabinetry, and under-cabinet lighting. Tidy and organized, suitable for modern home products.'
  },
  { 
    id: 'viet_kitchen', 
    label: 'Không Gian Bếp Việt', 
    desc: 'Gần gũi, truyền thống, phù hợp gia dụng, ẩm thực.',
    prompt: 'A realistic, warm traditional Vietnamese kitchen setting. Wooden cabinetry, a dining table with simple ceramic dishes, ingredients like fresh herbs and vegetables in the background. Soft, natural lighting creating a family atmosphere.'
  }
];

// Danh sách trang phục (Outfits)
const OUTFITS = [
  { id: 'keep', label: 'Giữ nguyên trang phục cũ', desc: 'Không thay đổi quần áo' },
  { id: 'daily_home', label: 'Đồ Mặc Nhà Hàng Ngày', desc: 'Thoải mái, giản dị (Pyjama, đồ bộ, áo thun)' },
  { id: 'uniform_polo', label: 'Áo Polo Đồng Phục', desc: 'Gọn gàng, chuyên nghiệp, phổ biến cho nhân viên sales' },
  { id: 'white_shirt', label: 'Sơ Mi Trắng & Quần Tây', desc: 'Lịch sự, tạo cảm giác tin cậy cao' },
  { id: 'smart_casual', label: 'Smart Casual (Blazer)', desc: 'Thanh lịch nhưng thoải mái, khoác Blazer nhẹ' },
  { id: 'office_dress', label: 'Váy Công Sở Thanh Lịch', desc: 'Duyên dáng, chuyên nghiệp (dành cho nữ)' },
  { id: 'livestream_trendy', label: 'Thời Trang Livestream', desc: 'Màu sắc nổi bật, bắt mắt, thu hút người xem' },
  { id: 'business_suit', label: 'Vest Doanh Nhân', desc: 'Bộ vest sang trọng, đẳng cấp' },
  { id: 'ao_dai', label: 'Áo Dài Việt Nam', desc: 'Trang phục truyền thống, phù hợp dịp lễ tết' },
  { id: 'casual_tshirt', label: 'Áo Thun Năng Động', desc: 'Đơn giản, quần jeans, thân thiện' },
  { id: 'sportswear', label: 'Đồ Thể Thao', desc: 'Quần áo tập gym/yoga khỏe khoắn' },
];

// Danh sách tư thế cầm (Poses)
const POSES = [
  { id: 'natural', label: 'Cầm Tự Nhiên', desc: 'AI tự quyết định cách cầm hợp lý nhất' },
  { id: 'one_hand_hold', label: 'Cầm 1 Tay', desc: 'Cầm sản phẩm chắc chắn bằng một tay' },
  { id: 'two_hands_present', label: '2 Tay Nâng Niu', desc: 'Hai tay nâng sản phẩm phía trước ngực' },
  { id: 'offering', label: 'Đưa Về Phía Trước', desc: 'Động tác mời, đưa sản phẩm về phía camera' },
  { id: 'holding_up', label: 'Giơ Cao', desc: 'Giơ sản phẩm lên cao ngang vai hoặc mặt' },
  { id: 'using_product', label: 'Đang Sử Dụng', desc: 'Tư thế đang dùng thử sản phẩm (nếu hợp lý)' },
];

const App = () => {
  const [personImage, setPersonImage] = useState(null);
  const [productImage, setProductImage] = useState(null);
  const [resultImage, setResultImage] = useState(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState('');
  const [statusMessage, setStatusMessage] = useState('');

  // State cho các lựa chọn
  const [selectedOutfit, setSelectedOutfit] = useState('keep');
  const [selectedPose, setSelectedPose] = useState('natural');
  const [selectedBackdrop, setSelectedBackdrop] = useState('cafe_outdoor'); 

  // Helper: Chuyển file sang Base64 và resize
  const processFile = (file) => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target.result;
        img.onload = () => {
          const canvas = document.createElement('canvas');
          const MAX_WIDTH = 1024; 
          const scaleSize = MAX_WIDTH / Math.max(img.width, MAX_WIDTH);
          canvas.width = img.width * scaleSize;
          canvas.height = img.height * scaleSize;
          const ctx = canvas.getContext('2d');
          ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
          const dataUrl = canvas.toDataURL(file.type);
          resolve({
            preview: dataUrl,
            base64: dataUrl.split(',')[1],
            mimeType: file.type
          });
        };
      };
      reader.onerror = error => reject(error);
    });
  };

  const handleFileUpload = async (e, type) => {
    const file = e.target.files[0];
    if (!file) return;

    try {
      const processed = await processFile(file);
      if (type === 'person') {
        setPersonImage(processed);
      } else {
        setProductImage(processed);
      }
      setResultImage(null);
      setError('');
    } catch (err) {
      setError('Lỗi khi xử lý ảnh. Vui lòng thử lại.');
    }
  };

  const handleGenerate = async () => {
    if (!personImage || !productImage) {
      setError('Vui lòng tải lên cả ảnh nhân vật và ảnh sản phẩm.');
      return;
    }

    setIsGenerating(true);
    setError('');
    setResultImage(null);
    setStatusMessage('Đang phân tích và tổng hợp hình ảnh...');

    try {
      const outfitConfig = OUTFITS.find(o => o.id === selectedOutfit);
      const poseConfig = POSES.find(p => p.id === selectedPose);
      const backdropConfig = BACKDROPS.find(b => b.id === selectedBackdrop);

      // Prompt nâng cao: Bao gồm cả xử lý nền
      const promptText = `
        ROLE: Expert Commercial Photographer & Digital Compositor.

        INPUTS:
        - Image 1: The Person (Reference for FACE ONLY).
        - Image 2: The Product.

        TASK:
        Generate a highly photorealistic commercial composite image.

        CRITICAL CONSTRAINTS (MUST FOLLOW):
        1. FACE PRESERVATION: Copy the face from Image 1 exactly. The identity must remain unchanged.
        2. BODY & OUTFIT: 
           ${selectedOutfit === 'keep' 
             ? 'Keep the original outfit from Image 1.' 
             : `Change the person's outfit to: ${outfitConfig.label} (${outfitConfig.desc}). Fit naturally.`}
        3. POSE & ACTION:
           The person holds the Product (Image 2) realistically.
           Pose Style: ${poseConfig.label} - ${poseConfig.desc}.
           Ensure anatomically correct hands and a natural grip.
        4. PRODUCT INTEGRATION:
           Place the product from Image 2 into the hands. Scale it realistically.
        5. BACKGROUND & ENVIRONMENT (NEW):
           Replace the original background completely.
           New Setting Setting: ${backdropConfig.prompt}
           CRITICAL: The lighting, shadows, and reflections on the person and the product must realistically match the new background setting to create a cohesive, photorealistic photograph.

        OUTPUT QUALITY: High resolution, commercial photography quality, realistic lighting and textures.
      `;

      const payload = {
        contents: [{
          parts: [
            { text: promptText },
            { inlineData: { mimeType: personImage.mimeType, data: personImage.base64 } },
            { inlineData: { mimeType: productImage.mimeType, data: productImage.base64 } }
          ]
        }],
        generationConfig: {
          responseModalities: ['TEXT', 'IMAGE'],
          temperature: 0.45
        }
      };

      setStatusMessage('Đang ghép ảnh và tái tạo bối cảnh chân thực...');

      const callApi = async (retryCount = 0) => {
        try {
          const response = await fetch(
            `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-image-preview:generateContent?key=${apiKey}`,
            {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify(payload)
            }
          );

          if (!response.ok) {
             if (response.status === 503 && retryCount < 3) {
                setStatusMessage(`Server bận, đang thử lại lần ${retryCount + 1}...`);
                await new Promise(r => setTimeout(r, 2000 * (retryCount + 1)));
                return callApi(retryCount + 1);
             }
             throw new Error(`Lỗi API: ${response.status}`);
          }

          const result = await response.json();
          const base64Data = result.candidates?.[0]?.content?.parts?.find(p => p.inlineData)?.inlineData?.data;

          if (base64Data) {
            setResultImage(`data:image/png;base64,${base64Data}`);
          } else {
            throw new Error("AI không thể tạo ảnh. Hãy thử lại với ảnh đầu vào rõ nét hơn.");
          }

        } catch (err) {
          throw err;
        }
      };

      await callApi();

    } catch (err) {
      console.error(err);
      setError(err.message || 'Đã xảy ra lỗi. Vui lòng thử lại.');
    } finally {
      setIsGenerating(false);
      setStatusMessage('');
    }
  };

  const handleReset = () => {
    setPersonImage(null);
    setProductImage(null);
    setResultImage(null);
    setError('');
    setSelectedOutfit('keep');
    setSelectedPose('natural');
    setSelectedBackdrop('cafe_outdoor');
  };

  const downloadImage = () => {
    if (resultImage) {
      const link = document.createElement('a');
      link.href = resultImage;
      link.download = `san-pham-${selectedOutfit}-${selectedBackdrop}.png`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-50 via-white to-purple-50 font-sans text-gray-800 p-4 md:p-8">
      <div className="max-w-6xl mx-auto bg-white/80 backdrop-blur-xl rounded-3xl shadow-2xl overflow-hidden border border-white">

        {/* Header */}
        <div className="bg-gradient-to-r from-violet-600 to-indigo-600 p-6 md:p-8 text-white relative overflow-hidden">
          <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-10"></div>
          <div className="relative z-10">
            <h1 className="text-3xl md:text-4xl font-extrabold mb-2 tracking-tight">AI Fashion & Product Studio</h1>
            <p className="text-indigo-100 max-w-2xl opacity-90 text-lg">
              Giữ mặt • Đổi trang phục • Chỉnh dáng cầm • <b>Thay bối cảnh chân thực</b>
            </p>
          </div>
        </div>

        <div className="p-6 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* LEFT COLUMN: Inputs & Options (7 cols) */}
          <div className="lg:col-span-7 space-y-6">

            {/* 1. Upload Images */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {/* Person */}
              <div className="space-y-2">
                <label className="flex items-center gap-2 font-bold text-gray-700 text-sm uppercase tracking-wide">
                  <User size={16} className="text-violet-600" /> Ảnh Nhân Vật
                </label>
                <div 
                  className={`relative group h-56 border-2 border-dashed rounded-2xl transition-all overflow-hidden bg-gray-50 flex flex-col items-center justify-center cursor-pointer
                    ${personImage ? 'border-violet-400 bg-violet-50' : 'border-gray-300 hover:border-violet-400 hover:bg-white'}`}
                >
                  {personImage ? (
                    <>
                      <img src={personImage.preview} alt="Person" className="h-full w-full object-contain p-2" />
                      <button onClick={(e) => { e.stopPropagation(); setPersonImage(null); }} className="absolute top-2 right-2 p-1.5 bg-gray-900/60 text-white rounded-full hover:bg-red-500 transition-colors"><X size={14} /></button>
                    </>
                  ) : (
                    <>
                      <div className="mb-2 p-3 bg-violet-100 text-violet-600 rounded-full group-hover:scale-110 transition-transform"><Upload size={24} /></div>
                      <span className="text-sm font-medium text-gray-500">Tải ảnh mẫu</span>
                    </>
                  )}
                  <input type="file" accept="image/*" className="absolute inset-0 opacity-0 cursor-pointer" onChange={(e) => handleFileUpload(e, 'person')} />
                </div>
              </div>

              {/* Product */}
              <div className="space-y-2">
                <label className="flex items-center gap-2 font-bold text-gray-700 text-sm uppercase tracking-wide">
                  <Box size={16} className="text-pink-600" /> Ảnh Sản Phẩm
                </label>
                <div 
                  className={`relative group h-56 border-2 border-dashed rounded-2xl transition-all overflow-hidden bg-gray-50 flex flex-col items-center justify-center cursor-pointer
                    ${productImage ? 'border-pink-400 bg-pink-50' : 'border-gray-300 hover:border-pink-400 hover:bg-white'}`}
                >
                  {productImage ? (
                    <>
                      <img src={productImage.preview} alt="Product" className="h-full w-full object-contain p-2" />
                      <button onClick={(e) => { e.stopPropagation(); setProductImage(null); }} className="absolute top-2 right-2 p-1.5 bg-gray-900/60 text-white rounded-full hover:bg-red-500 transition-colors"><X size={14} /></button>
                    </>
                  ) : (
                    <>
                      <div className="mb-2 p-3 bg-pink-100 text-pink-600 rounded-full group-hover:scale-110 transition-transform"><Upload size={24} /></div>
                      <span className="text-sm font-medium text-gray-500">Tải ảnh SP</span>
                    </>
                  )}
                  <input type="file" accept="image/*" className="absolute inset-0 opacity-0 cursor-pointer" onChange={(e) => handleFileUpload(e, 'product')} />
                </div>
              </div>
            </div>

            <div className="h-px bg-gray-200 my-2"></div>

            {/* 2. Configuration Options */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

              {/* Outfit Selection */}
              <div className="space-y-2">
                <label className="flex items-center gap-2 font-bold text-gray-800">
                  <Shirt size={20} className="text-teal-600" /> Trang Phục
                </label>
                <div className="space-y-2 max-h-40 overflow-y-auto pr-1 custom-scrollbar">
                  {OUTFITS.map((item) => (
                    <div 
                      key={item.id}
                      onClick={() => setSelectedOutfit(item.id)}
                      className={`p-2.5 rounded-xl border cursor-pointer transition-all flex flex-col gap-1
                        ${selectedOutfit === item.id 
                          ? 'border-teal-500 bg-teal-50 shadow-sm ring-1 ring-teal-200' 
                          : 'border-gray-200 hover:bg-gray-50'}`}
                    >
                      <span className="font-semibold text-sm text-gray-800">{item.label}</span>
                      <span className="text-xs text-gray-500 truncate">{item.desc}</span>
                    </div>
                  ))}
                </div>
              </div>

              {/* Pose Selection */}
              <div className="space-y-2">
                <label className="flex items-center gap-2 font-bold text-gray-800">
                  <Hand size={20} className="text-orange-500" /> Cách Cầm
                </label>
                <div className="space-y-2 max-h-40 overflow-y-auto pr-1 custom-scrollbar">
                  {POSES.map((item) => (
                    <div 
                      key={item.id}
                      onClick={() => setSelectedPose(item.id)}
                      className={`p-2.5 rounded-xl border cursor-pointer transition-all flex flex-col gap-1
                        ${selectedPose === item.id 
                          ? 'border-orange-500 bg-orange-50 shadow-sm ring-1 ring-orange-200' 
                          : 'border-gray-200 hover:bg-gray-50'}`}
                    >
                      <span className="font-semibold text-sm text-gray-800">{item.label}</span>
                      <span className="text-xs text-gray-500 truncate">{item.desc}</span>
                    </div>
                  ))}
                </div>
              </div>

               {/* Backdrop Selection (New) */}
               <div className="space-y-2 md:col-span-2">
                <label className="flex items-center gap-2 font-bold text-gray-800">
                  <Layers size={20} className="text-blue-600" /> Bối Cảnh (Backdrop)
                </label>
                <div className="grid grid-cols-2 gap-2 max-h-48 overflow-y-auto pr-1 custom-scrollbar">
                  {BACKDROPS.map((item) => (
                    <div 
                      key={item.id}
                      onClick={() => setSelectedBackdrop(item.id)}
                      className={`p-2.5 rounded-xl border cursor-pointer transition-all flex flex-col gap-1 h-full
                        ${selectedBackdrop === item.id 
                          ? 'border-blue-500 bg-blue-50 shadow-sm ring-1 ring-blue-200' 
                          : 'border-gray-200 hover:bg-gray-50'}`}
                    >
                      <span className="font-semibold text-sm text-gray-800">{item.label}</span>
                      <span className="text-xs text-gray-500 line-clamp-2">{item.desc}</span>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Error Message */}
            {error && (
              <div className="flex items-center gap-2 text-red-600 bg-red-50 px-4 py-3 rounded-xl border border-red-100 animate-pulse">
                <AlertCircle size={18} />
                <span className="text-sm font-medium">{error}</span>
              </div>
            )}
          </div>

          {/* RIGHT COLUMN: Action & Result (5 cols) */}
          <div className="lg:col-span-5 flex flex-col gap-6">

            {/* Generate Button */}
            <div className="bg-gray-50 p-6 rounded-3xl border border-gray-100 text-center space-y-4 sticky top-8">
              <button
                onClick={handleGenerate}
                disabled={!personImage || !productImage || isGenerating}
                className={`
                  w-full relative overflow-hidden group py-4 rounded-2xl text-lg font-bold text-white shadow-xl transition-all transform
                  ${(!personImage || !productImage) 
                    ? 'bg-gray-300 cursor-not-allowed' 
                    : isGenerating 
                      ? 'bg-gray-800 cursor-wait' 
                      : 'bg-gradient-to-r from-violet-600 to-fuchsia-600 hover:scale-[1.02] active:scale-95'}
                `}
              >
                <span className="relative z-10 flex items-center justify-center gap-2">
                  {isGenerating ? (
                    <>
                      <RefreshCw className="animate-spin" size={20} />
                      Đang xử lý...
                    </>
                  ) : (
                    <>
                      <Sparkles className="group-hover:rotate-12 transition-transform" size={20} />
                      Tạo Ảnh Mới
                    </>
                  )}
                </span>
              </button>

              {isGenerating ? (
                 <p className="text-sm text-violet-600 font-medium animate-pulse">{statusMessage}</p>
              ) : (
                 <p className="text-xs text-gray-400">Thời gian tạo: 15-25 giây</p>
              )}
            </div>

            {/* Result Display */}
            <div className="flex-1 min-h-[400px] bg-gray-100 rounded-3xl border-2 border-dashed border-gray-200 flex items-center justify-center relative overflow-hidden group">
              {resultImage ? (
                <>
                  <img src={resultImage} alt="Result" className="w-full h-full object-cover rounded-3xl" />

                  {/* Result Actions */}
                  <div className="absolute bottom-4 left-1/2 -translate-x-1/2 flex gap-3 opacity-0 group-hover:opacity-100 transition-all duration-300 translate-y-2 group-hover:translate-y-0">
                    <button 
                      onClick={downloadImage}
                      className="bg-white text-gray-900 px-5 py-2.5 rounded-full font-bold flex items-center gap-2 shadow-lg hover:bg-gray-50"
                    >
                      <Download size={16} /> Tải Về
                    </button>
                    <button 
                      onClick={handleReset}
                      className="bg-gray-900 text-white px-5 py-2.5 rounded-full font-bold flex items-center gap-2 shadow-lg hover:bg-gray-800"
                    >
                      <RefreshCw size={16} /> Thử Lại
                    </button>
                  </div>
                </>
              ) : (
                <div className="text-center text-gray-400 p-8">
                  <div className="w-16 h-16 bg-gray-200 rounded-full flex items-center justify-center mx-auto mb-3">
                    <ImageIcon size={32} />
                  </div>
                  <p className="font-medium">Kết quả sẽ hiện ở đây</p>
                  <p className="text-sm mt-1">Cấu hình và bấm nút tạo</p>
                </div>
              )}
            </div>

          </div>
        </div>
      </div>

      <div className="text-center text-gray-400 mt-8 text-sm font-medium">
        Powered by Gemini 2.5 Flash Image Preview
      </div>
    </div>
  );
};

export default App;

