    <script>
        const API_URL = "https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-image-preview:generateContent";
        const apiKey = ""; // API Key sẽ được tự động cung cấp

        let base64Image = null; // Lưu trữ Base64 của ảnh đã tải lên

        const originalImageContainer = document.getElementById('originalImageContainer');
        const resultImage = document.getElementById('resultImage');
        const resultPlaceholder = document.getElementById('resultPlaceholder');
        const processButton = document.getElementById('processButton');
        const loadingIndicator = document.getElementById('loadingIndicator');
        const messageBox = document.getElementById('messageBox');

        // BIẾN MỚI
        const clearButton = document.getElementById('clearButton');
        const downloadButton = document.getElementById('downloadButton');

        // Hàm hiển thị thông báo
        function showMessage(message, type = 'warning') {
            messageBox.textContent = message;
            // Đảm bảo thông báo hiển thị đúng màu cho trạng thái success/error
            const bgClass = type === 'error' ? 'bg-red-100 text-red-800' : (type === 'success' ? 'bg-green-100 text-green-800' : 'bg-yellow-100 text-yellow-800');
            messageBox.className = `p-4 mt-4 rounded-lg ${bgClass}`;
            messageBox.classList.remove('hidden');
        }

        // Hàm ẩn thông báo
        function hideMessage() {
            messageBox.classList.add('hidden');
        }

        // HÀM MỚI: Xóa ảnh và reset trạng thái
        function clearImage() {
            base64Image = null;
            document.getElementById('imageUpload').value = ''; // Xóa file đã chọn

            // Reset ảnh gốc
            originalImageContainer.innerHTML = '<p class="text-gray-400">Chưa có ảnh</p>';

            // Reset ảnh kết quả
            resultImage.classList.add('hidden');
            resultImage.src = '';
            resultPlaceholder.textContent = 'Chờ xử lý';
            resultPlaceholder.classList.remove('hidden');

            // Reset nút và thông báo
            processButton.disabled = true;
            processButton.textContent = 'Tách Nền Ngay';
            clearButton.classList.add('hidden');
            downloadButton.classList.add('hidden');
            hideMessage();
        }


        // Hàm chuyển đổi file ảnh thành Base64 và hiển thị ảnh gốc
        function previewImage(event) {
            const file = event.target.files[0];
            if (!file) {
                clearImage(); // Nếu hủy chọn file, reset
                return;
            }

            // Kiểm tra kích thước file (tối đa 4MB)
            if (file.size > 4 * 1024 * 1024) {
                showMessage("Kích thước file quá lớn. Vui lòng chọn ảnh nhỏ hơn 4MB.", 'error');
                processButton.disabled = true;
                return;
            }

            hideMessage();
            resultImage.classList.add('hidden');
            resultPlaceholder.textContent = 'Chờ xử lý';
            resultPlaceholder.classList.remove('hidden');
            processButton.disabled = false;
            processButton.textContent = 'Tách Nền Ngay';

            // Hiển thị nút Clear và ẩn nút Download
            clearButton.classList.remove('hidden');
            downloadButton.classList.add('hidden');


            const reader = new FileReader();
            reader.onload = function(e) {
                // Lấy phần Base64 (sau "base64,")
                base64Image = e.target.result.split(',')[1]; 

                // Hiển thị ảnh gốc
                originalImageContainer.innerHTML = `<img src="${e.target.result}" alt="Ảnh gốc sản phẩm" class="rounded-lg">`;
            };
            reader.readAsDataURL(file);
        }

        /**
         * Hàm gọi API để tách nền ảnh
         */
        async function callImageEditingAPI() {
            if (!base64Image) {
                showMessage("Vui lòng tải lên một hình ảnh trước.", 'error');
                return null;
            }

            // Prompt được tối ưu để yêu cầu xóa nền (trong suốt)
            const prompt = "Remove the background from the product in the image. The product should be sharp and well-defined, and the background should be completely removed (transparent). Output a PNG image.";

            const payload = {
                contents: [{
                    parts: [
                        { text: prompt },
                        {
                            inlineData: {
                                // Yêu cầu output là PNG để đảm bảo hỗ trợ kênh alpha (trong suốt)
                                mimeType: "image/png", 
                                data: base64Image
                            }
                        }
                    ]
                }],
                generationConfig: {
                    responseModalities: ['TEXT', 'IMAGE']
                },
            };

            const url = `${API_URL}?key=${apiKey}`;
            const maxRetries = 5;
            let delay = 1000; // 1s

            for (let i = 0; i < maxRetries; i++) {
                try {
                    const response = await fetch(url, {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify(payload)
                    });

                    if (response.status === 429) {
                        // Xử lý lỗi Rate Limit với Exponential Backoff
                        if (i < maxRetries - 1) {
                            await new Promise(resolve => setTimeout(resolve, delay));
                            delay *= 2;
                            continue;
                        } else {
                            throw new Error("API bị giới hạn tốc độ. Vui lòng thử lại sau.");
                        }
                    }

                    if (!response.ok) {
                        const errorBody = await response.json();
                        throw new Error(`Lỗi API: ${response.status} - ${errorBody.error?.message || 'Lỗi không xác định'}`);
                    }

                    const result = await response.json();
                    return result;

                } catch (error) {
                    console.error(`Lần thử ${i + 1} thất bại:`, error.message);
                    if (i === maxRetries - 1) {
                        throw error;
                    }
                    await new Promise(resolve => setTimeout(resolve, delay));
                    delay *= 2;
                }
            }
            return null; // Should not reach here
        }

        /**
         * Xử lý chính khi người dùng nhấn nút
         */
        async function processImage() {
            if (!base64Image) {
                showMessage("Vui lòng tải lên một hình ảnh.", 'error');
                return;
            }

            hideMessage();
            processButton.disabled = true;
            processButton.textContent = 'Đang Xử Lý...';
            loadingIndicator.classList.remove('hidden');
            resultPlaceholder.textContent = 'Đang xử lý tách nền...';
            downloadButton.classList.add('hidden'); // Ẩn nút download trong khi xử lý

            try {
                const result = await callImageEditingAPI();

                if (result && result.candidates && result.candidates.length > 0) {
                    const base64Data = result.candidates[0]?.content?.parts?.find(p => p.inlineData)?.inlineData?.data;

                    if (base64Data) {
                        const imageUrl = `data:image/png;base64,${base64Data}`;
                        resultImage.src = imageUrl;
                        resultImage.classList.remove('hidden');
                        resultPlaceholder.classList.add('hidden');

                        // Cập nhật và hiển thị nút Tải Xuống
                        downloadButton.href = imageUrl;
                        downloadButton.classList.remove('hidden');

                        showMessage("Tách nền thành công! Bạn có thể tải xuống ảnh PNG.", 'success');
                        messageBox.classList.remove('bg-yellow-100', 'text-yellow-800');
                        messageBox.classList.add('bg-green-100', 'text-green-800');

                    } else {
                        throw new Error("Không nhận được dữ liệu ảnh từ mô hình.");
                    }
                } else {
                    throw new Error("Phản hồi từ API không hợp lệ hoặc rỗng.");
                }

            } catch (error) {
                console.error("Lỗi trong quá trình xử lý ảnh:", error);
                showMessage(`Lỗi: ${error.message}. Vui lòng thử lại.`, 'error');
                resultPlaceholder.textContent = 'Xử lý thất bại';
                resultImage.classList.add('hidden');
                downloadButton.classList.add('hidden'); // Đảm bảo ẩn khi có lỗi
            } finally {
                processButton.disabled = false;
                processButton.textContent = 'Tách Nền Ngay';
                loadingIndicator.classList.add('hidden');
            }
        }
    </script>
</body>
