import React, { useState, useCallback } from 'react';
import { Upload, ImageIcon, Sparkles } from 'lucide-react';

// Chức năng chuyển đổi Base64 sang ArrayBuffer (dành cho logic fetch API) - Không dùng nhưng giữ lại như một hàm tiện ích
const base64ToArrayBuffer = (base64) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes.buffer;
};

// Hàm fetch với cơ chế backoff (để xử lý lỗi API)
const fetchWithBackoff = async (url, options, maxRetries = 5) => {
    let delay = 1000;
    for (let i = 0; i < maxRetries; i++) {
        try {
            const response = await fetch(url, options);
            if (response.status === 429 && i < maxRetries - 1) {
                console.warn(`Rate limit exceeded. Retrying in ${delay / 1000}s...`);
                await new Promise(resolve => setTimeout(resolve, delay));
                delay *= 2; // Exponential backoff
                continue;
            }
            if (!response.ok) {
                const errorText = await response.text();
                throw new Error(`HTTP error! Status: ${response.status}. Details: ${errorText}`);
            }
            return response;
        } catch (error) {
            if (i === maxRetries - 1) throw error;
            console.error(`Fetch attempt failed: ${error.message}. Retrying...`);
            await new Promise(resolve => setTimeout(resolve, delay));
            delay *= 2;
        }
    }
    throw new Error('API request failed after multiple retries.');
};

