              </button>

              {/* Khu vực hiển thị kết quả */}
              <div className="flex-1 bg-white rounded-2xl shadow-xl border border-indigo-50 flex flex-col min-h-[400px]">
                <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50 rounded-t-2xl">
                  <h2 className="font-bold text-slate-700 flex items-center">
                    <BookOpen className="w-5 h-5 mr-2 text-indigo-500" /> 3. Nội dung AI tạo
                  </h2>
                  {generatedContent && (
                    <div className="flex space-x-2">
                        <button 
                            onClick={generateContent}
                            disabled={isLoading}
                            className={`flex items-center text-xs px-3 py-1.5 rounded-lg transition-all border ${isLoading ? 'bg-slate-200 text-slate-500' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-100'}`}
                            title="Tạo lại nội dung"
                        >
                            <RefreshCw className="w-4 h-4" />
                        </button>

                        <button 
                            onClick={copyToClipboard}
                            className={`flex items-center text-sm px-3 py-1.5 rounded-lg transition-all ${copied ? 'bg-green-100 text-green-700' : 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-50'}`}
                        >
                          {copied ? <Check className="w-4 h-4 mr-1" /> : <Copy className="w-4 h-4 mr-1" />}
                          {copied ? 'Đã sao chép' : 'Sao chép'}
                        </button>
                    </div>
                  )}
                </div>

                <div className="p-6 flex-1 overflow-y-auto">
                  {error && (
                    <div className="bg-red-50 text-red-700 p-4 rounded-xl flex items-start mb-4 border border-red-300 shadow-sm">
                      <AlertCircle className="w-5 h-5 mr-2 flex-shrink-0 mt-0.5" />
                      <span className="text-sm font-medium">{error}</span>
                    </div>
                  )}

                  {!generatedContent && !isLoading && !error && (
                    <div className="h-full flex flex-col items-center justify-center text-slate-400 opacity-60">
                      <PenTool className="w-16 h-16 mb-4" />
                      <p>Vui lòng điền đầy đủ thông tin sản phẩm và nhấn nút tạo.</p>
                      <p className="text-xs mt-1">AI sẽ giúp bạn bùng nổ doanh số!</p>
                    </div>
                  )}

                  {isLoading && (
                    <div className="space-y-4 p-4 rounded-xl bg-slate-50 shadow-inner">
                      <p className="text-indigo-600 font-semibold flex items-center">
                         <Loader2 className="w-4 h-4 mr-2 animate-spin" /> AI đang viết bài quảng cáo đỉnh cao...
                      </p>
                      <div className="h-4 bg-slate-200 rounded w-3/4 animate-pulse"></div>
                      <div className="h-4 bg-slate-200 rounded w-full animate-pulse delay-75"></div>
                      <div className="h-24 bg-slate-200 rounded w-full animate-pulse delay-150"></div>
                      <div className="h-4 bg-slate-200 rounded w-5/6 animate-pulse delay-200"></div>
                    </div>
                  )}

                  {generatedContent && !isLoading && (
                    <div className="text-base text-slate-800 whitespace-pre-wrap leading-relaxed">
                      {/* Đảm bảo nội dung luôn là một khối text duy nhất, dễ dàng copy-paste */}
                      {generatedContent}
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

export default ContentGeniusAI;
